/* oms-item-itemgroup-sql-oracle.xml - selectItemGroupCode */
SELECT 	ICGRPNM
	   ,ICGRPKEY
FROM 	TORDER_MST_ICGR
WHERE   OWKEY = #{owkey}

/* oms-item-itemgroup-sql-oracle.xml - selectItemGroup */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT'0' AS CHK , OWKEY , (SELECT OWNM FROM TORDER_MST_OW OW WHERE OW.OWKEY = TORDER_MST_ICGR.OWKEY) AS OWNM , UPDATEDATE , INSERTDATE , INSERTURKEY , UPDATEURKEY , ICGRPTYPE , ICGRPNM , ICGRPKEY , CLOSDATE , IFYN FROM TORDER_MST_ICGR
#{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		/* oms-item-itemgroup-sql-oracle.xml - selectItemGroupCount */
		SELECT 	COUNT(1)  
  		FROM 	TORDER_MST_ICGR 


		   		#{SEARCH_CONDITION}

		/* oms-item-itemgroup-sql-oracle.xml - selectCountTOmsinMstIcgrXCt */
		SELECT 	COUNT(1)  
  		FROM 	TORDER_MST_ICGRXCT
	    WHERE	1 = 1
	    AND     OWKEY = #{owkey}
	    AND     ICGRPKEY = #{icgrpkey}
	    AND     ICGRPTYPE = #{icgrptype}

mapper.insert:
/* oms-item-itemgroup-sql-oracle.xml - insertTOmsinMstIcgr */
INSERT INTO TORDER_MST_ICGR	(
	UPDATEURKEY
	,UPDATEDATE
	,INSERTURKEY
	,INSERTDATE
	,ICGRPTYPE
	,ICGRPNM
	,ICGRPKEY
	,CLOSDATE
	,OWKEY
)
VALUES (
	#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{icgrptype}
	,#{icgrpnm}
	,#{icgrpkey}
	,SUBSTR(#{closdate}, 0, 14)
	,#{owkey}
)

mapper.update:
		/* oms-item-itemgroup-sql-oracle.xml - updateTOmsinMstIcgr */
		UPDATE 	TORDER_MST_ICGR 
		SET		UPDATEURKEY = #{surkey}
				,UPDATEDATE  = #{sysdate}
				,ICGRPNM    = #{icgrpnm}
				,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
	    WHERE 	OWKEY = #{owkey}
    	AND 	ICGRPKEY = #{icgrpkey}
        AND 	ICGRPTYPE = #{icgrptype}

