mapper.update:
		/* wms-item-itemgroup-sql-oracle.xml - deleteTAWorkMstIcctg */
		UPDATE TWORK_MST_CTG
		   SET DELYN = 'Y'
		     , UPDATEURKEY = #{surkey} 
             , UPDATEDATE = #{sysdate}
     	 WHERE OWKEY = #{owkey}
     	   AND ICGRKEY IS NOT NULL
     	   AND ICGRKEY = #{icgrpkey}

			AND CTKEY = #{ctkey}

mapper.insert:
	/* wms-item-itemgroup-sql-oracle.xml - insertTWorkMstIcgr */
   INSERT INTO TWORK_MST_ICGR (
				 UPDATEURKEY
				,UPDATEDATE
				,INSERTURKEY
				,INSERTDATE
				,ICGRTYPE
				,ICGRNAME
				,ICGRKEY
				,CTKEY
				,CLOSDATE
				,OWKEY
				,SAMFILENAME
		  ) VALUES (
				 #{surkey}
				,#{sysdate}
				,#{surkey}
				,#{sysdate}
				,#{icgrptype}
				,#{icgrpnm}
				,#{icgrpkey}
				,#{ctkey}
				,SUBSTR(#{closdate}, 0, 14)
				,#{owkey}
				,#{samfilename}
		  )
		  ON CONFLICT (CTKEY, OWKEY, ICGRKEY, ICGRTYPE) DO UPDATE SET
                 UPDATEURKEY = #{surkey}
                 ,UPDATEDATE = #{sysdate}
                 ,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
                 ,SAMFILENAME = #{samfilename}
                 ,ICGRNAME = #{icgrpnm}

mapper.update:
		/* wms-item-itemgroup-sql-oracle.xml - updateTWorkMstIcgr */
		UPDATE 	TWORK_MST_ICGR 
		SET		UPDATEURKEY = #{surkey}
				,UPDATEDATE  = #{sysdate}
				,ICGRNAME    = #{icgrpnm}
				,SAMFILENAME = #{samfilename}
				,CLOSDATE = SUBSTR(#{closdate}, 0, 14)
	    WHERE 	OWKEY = #{owkey}
    	AND 	ICGRKEY = #{icgrpkey}
        AND 	ICGRTYPE = #{icgrptype}

/* wms-item-itemgroup-sql-oracle.xml - updateTAWorkMstIcctg */ UPDATE TWORK_MST_CTG M SET ( CTGNAME /*상품대/중/소명*/ , UPPERCTGKEY /*상위상품분류*/ , ICGRKEY /*상품그룹코드*/ , DELYN , UPDATEDATE /*수정일시*/ , UPDATEURKEY /*수정사용자*/ ) = ( SELECT CG.CTGNM /*상품대/중/소명*/ , CG.UPPERCTGKEY /*상위상품분류*/ , CG.ICGRPKEY , 'N' AS DELYN , #{sysdate} AS UPDATEDATE /*수정일시*/ , #{surkey} AS UPDATEURKEY /*수정사용자 ID*/ FROM (
SELECT #{item.owkey} AS OWKEY , #{item.icgrptype} AS ICGRTYPE , #{item.icgrpkey} AS ICGRKEY , #{item.ctkey} AS CTKEY
) T JOIN TADMIN_MST_CTG CG ON T.OWKEY = CG.OWKEY AND T.ICGRKEY = CG.ICGRPKEY WHERE T.OWKEY = M.OWKEY AND T.CTKEY = M.CTKEY AND CG.CTGKEY = M.CTGKEY ) WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.owkey} AS OWKEY , #{item.icgrptype} AS ICGRTYPE , #{item.icgrpkey} AS ICGRKEY , #{item.ctkey} AS CTKEY
) T JOIN TADMIN_MST_CTG CG ON T.OWKEY = CG.OWKEY AND T.ICGRKEY = CG.ICGRPKEY WHERE T.OWKEY = M.OWKEY AND T.CTKEY = M.CTKEY AND CG.CTGKEY = M.CTGKEY )

mapper.insert:
/* wms-item-itemgroup-sql-oracle.xml - insertTAWorkMstIcctg */ INSERT INTO TWORK_MST_CTG ( CTKEY /*센터코드*/ , CTGKEY /*상품대/중/소코드*/ , CTGLEVEL /*상품대/중/소구분*/ , OWKEY /*화주*/ , CTGNAME /*상품대/중/소명*/ , UPPERCTGKEY /*상위상품분류*/ , URKEY /*담당MD사번*/ , CLOSDATE /*종료일시*/ , DELYN /*삭제여부*/ , ICGRKEY /*상품그룹코드*/ , INSERTDATE /*입력일시*/ , INSERTURKEY /*입력사용자*/ , UPDATEDATE /*수정일시*/ , UPDATEURKEY /*수정사용자*/ ) SELECT TT.CTKEY /*센터코드*/ , TT.CTGKEY /*상품대/중/소코드*/ , TT.CTGLV /*상품대/중/소구분*/ , TT.OWKEY , TT.CTGNM /*상품대/중/소명*/ , TT.UPPERCTGKEY /*상위상품분류*/ , NULL AS URKEY , #{closdate} AS CLOSDATE , 'N' AS DELYN , TT.ICGRPKEY , #{sysdate} AS INSERTDATE /*입력일시*/ , #{surkey} AS INSERTURKEY /*입력사용자 ID*/ , #{sysdate} AS UPDATEDATE /*수정일시*/ , #{surkey} AS UPDATEURKEY /*수정사용자 ID*/ FROM ( SELECT LI.CTGKEY /*상품대/중/소코드*/ , LI.CTGLV /*상품대/중/소구분*/ , LI.OWKEY , T.CTKEY , LI.CTGNM /*상품대/중/소명*/ , LI.UPPERCTGKEY /*상위상품분류*/ , LI.ICGRPKEY , CASE WHEN M.OWKEY IS NULL THEN 'Y' ELSE 'N' END AS SAVEYN FROM (
SELECT #{item.owkey} AS OWKEY , #{item.icgrptype} AS ICGRTYPE , #{item.icgrpkey} AS ICGRKEY , #{item.ctkey} AS CTKEY
) T JOIN TADMIN_MST_CTG LI ON T.OWKEY = LI.OWKEY AND T.ICGRKEY = LI.ICGRPKEY LEFT JOIN TWORK_MST_CTG M ON LI.OWKEY = M.OWKEY AND LI.CTGKEY = M.CTGKEY AND T.CTKEY = M.CTKEY ) TT WHERE TT.SAVEYN = 'Y'
